export const PERIMETER_BOTTOM: string[] = [
  ...Array.from({ length: 8 }, (_, i) => `B${73 + i}`), // B73-B80
  ...Array.from({ length: 15 }, (_, i) => `B${1 + i}`), // B1-B15
];
export const PERIMETER_LEFT: string[] = Array.from({ length: 16 }, (_, i) => `B${31 - i}`); // B31-B16